queries.sparql:
PREFIX : <http://ambrosia.example.org/agriculture#>
PREFIX p: <http://ambrosia.example.org/agriculture/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?species_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasFish_Species ?child ; p:hasAquaculture_Facility ?parent . } GROUP BY ?child }
  ?child p:name ?species_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Aquaculture_Facility } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/agriculture#>
PREFIX p: <http://ambrosia.example.org/agriculture/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?name ?species_name WHERE {
  ?aquaculture_facility_fish_species a :Aquaculture_Facility_Fish_Species .
  ?fish_species a :Species .
  ?aquaculture_facility_fish_species p:hasFish_Species ?fish_species .
  ?aquaculture_facility a :Aquaculture_Facility .
  ?aquaculture_facility_fish_species p:hasAquaculture_Facility ?aquaculture_facility .
  ?aquaculture_facility p:name ?name .
  ?fish_species p:name ?species_name .
} }
  collective: { SELECT ?species_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasFish_Species ?child ; p:hasAquaculture_Facility ?parent . } GROUP BY ?child }
  ?child p:name ?species_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Aquaculture_Facility } }
  FILTER(?nf = ?total)
} }
}
